CREATE TABLE users (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,email VARCHAR(255) NOT NULL UNIQUE,password_hash VARCHAR(255) NOT NULL,role VARCHAR(32) NOT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE channels (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,description TEXT NULL,rtmp_url VARCHAR(512) NOT NULL,stream_key VARCHAR(512) NOT NULL,status VARCHAR(32) NOT NULL DEFAULT 'stopped',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE videos (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,title VARCHAR(255) NOT NULL,filename VARCHAR(255) NOT NULL UNIQUE,original_filename VARCHAR(255) NOT NULL,mime_type VARCHAR(120) NOT NULL,size_bytes BIGINT UNSIGNED NOT NULL,duration_seconds INT UNSIGNED NULL,thumbnail_filename VARCHAR(255) NULL,status VARCHAR(32) NOT NULL,source_url TEXT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE playlists (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(255) NOT NULL,description TEXT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE playlist_videos (playlist_id BIGINT UNSIGNED NOT NULL,video_id BIGINT UNSIGNED NOT NULL,position INT UNSIGNED NOT NULL,PRIMARY KEY(playlist_id,video_id),CONSTRAINT fk_pv_playlist FOREIGN KEY(playlist_id) REFERENCES playlists(id) ON DELETE CASCADE,CONSTRAINT fk_pv_video FOREIGN KEY(video_id) REFERENCES videos(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE streams (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,channel_id BIGINT UNSIGNED NOT NULL,playlist_id BIGINT UNSIGNED NOT NULL,status VARCHAR(32) NOT NULL,restart_count INT UNSIGNED NOT NULL DEFAULT 0,pid INT NULL,scheduled_start DATETIME NULL,scheduled_end DATETIME NULL,started_at DATETIME NULL,stopped_at DATETIME NULL,stop_requested BOOLEAN NOT NULL DEFAULT FALSE,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,CONSTRAINT fk_stream_channel FOREIGN KEY(channel_id) REFERENCES channels(id),CONSTRAINT fk_stream_playlist FOREIGN KEY(playlist_id) REFERENCES playlists(id),INDEX idx_stream_status(status)) ENGINE=InnoDB;
CREATE TABLE settings (`key` VARCHAR(120) PRIMARY KEY,`value` TEXT NOT NULL,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB;
